fun dungeonGame(grid: Array<IntArray>): Int {
    val m = grid.size
    if (m == 0) return 0
    val n = grid[0].size

    val dp = Array(m) { IntArray(n) }

    for (i in m - 1 downTo 0) {
        for (j in n - 1 downTo 0) {
